import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class FunctionSignatureRuleReproductionTest {
    private val functionSignatureWrappingRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    @Test
    fun `Issue reproduction - Missing whitespace before function body is inserted in wrong place in AST`() {
        val code =
            """
            class UampNotificationManager(
                private val context: Context,
                sessionToken: MediaSessionCompat.Token,
                notificationListener: PlayerNotificationManager.NotificationListener,
            ) {
                fun showNotificationForPlayer(player: Player){
                    notificationManager.setPlayer(player)
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            class UampNotificationManager(
                private val context: Context,
                sessionToken: MediaSessionCompat.Token,
                notificationListener: PlayerNotificationManager.NotificationListener,
            ) {
                fun showNotificationForPlayer(player: Player) {
                    notificationManager.setPlayer(player)
                }
            }
            """.trimIndent()

        functionSignatureWrappingRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .addAdditionalRuleProvider { FunctionStartOfBodySpacingRule() }
            // curly-spacing is not easily available here, but FunctionSignatureRule and FunctionStartOfBodySpacingRule are the main ones involved in the conflict
            .hasLintViolation(6, 50, "Expected a single space before body block")
            .isFormattedAs(formattedCode)
    }
}
